#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int a[4];
        for(int i=0;i<4;i++) scanf("%d", &a[i]);
        int freq[4]; // at most 4 distinct values
        int distinct=0;
        for(int i=0;i<4;i++){
            int found=0;
            for(int j=0;j<distinct;j++) if(a[i]==freq[j]){found=j; break;}
            if(found==0 && (distinct==0 || a[i]!=freq[found-1])){
                // not found, add new entry
                freq[distinct++] = a[i];
            }
        }
        // simpler: compute max frequency directly
        int maxFreq=1;
        for(int i=0;i<4;i++){
            int cnt=0;
            for(int j=0;j<4;j++) if(a[i]==a[j]) cnt++;
            if(cnt>maxFreq) maxFreq=cnt;
        }
        int ans = (maxFreq==4)?0:(maxFreq==3)?1:2;
        printf("%d\n", ans);
    }
    return 0;
}

