    while(T--){
        int a[4]; for(int i=0;i<4;i++) cin>>a[i];
        unordered_map<int,int> mp;
        int maxFreq=0;
        for(int x: a){
            maxFreq = max(maxFreq, ++mp[x]);
        }
        int ans = (maxFreq==4)?0:(maxFreq==3)?1:2;
        cout<<ans<<"\n";
    }
