import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = [int(next(it)) for _ in range(4)]
        freq = {}
        max_freq = 0
        for x in a:
            freq[x] = freq.get(x, 0) + 1
            if freq[x] > max_freq:
                max_freq = freq[x]
        if max_freq == 4:
            out.append('0')
        elif max_freq == 3:
            out.append('1')
        else:
            out.append('2')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

